#include <cstdio>

class Handle {
public:
    Handle() = default;
    ~Handle() {
        if (fp_) std::fclose(fp_);
    }
    Handle(const Handle&) = delete;
    Handle& operator=(const Handle&) = delete;
    Handle(Handle&& other) noexcept : fp_(other.fp_) { other.fp_ = nullptr; }
    Handle& operator=(Handle&& other) noexcept {
        if (this != &other) {
            if (fp_) std::fclose(fp_);
            fp_ = other.fp_;
            other.fp_ = nullptr;
        }
        return *this;
    }
private:
    std::FILE* fp_ = nullptr;
};
